    const addClient = useCallback((clientData: Omit<Client, 'id'>) => {
        const newClient: Client = { ...clientData, id: `cli-${Date.now()}`, createdAt: new Date().toISOString() };
        setMainClients(prev => [newClient, ...prev]);
        return newClient;
