        const newOpportunityTask: Task = {
            id: `task-opp-${opportunityId}`,
            title: `Cierre Oportunidad: ${clientName}`,
            description: `Valor estimado: €${newOpportunity.value.toLocaleString('es-ES')}`,
            dueDate: newOpportunity.closeDate,
