    const convertLeadToOpportunity = useCallback((
        leadId: string, 
        opportunityData: { products: OpportunityProduct[], closeDate: string, stage: OpportunityStage, salespersonId: string }
    ): Opportunity | null => {
        const lead = mainLeads.find(l => l.id === leadId);
        if (!lead) return null;

        const value = opportunityData.products.reduce((sum, p) => sum + p.price * p.quantity, 0);

        const newOpp = addOpportunity({
            products: opportunityData.products,
            closeDate: opportunityData.closeDate,
            salespersonId: opportunityData.salespersonId,
            stage: opportunityData.stage,
            value: value,
            originalLeadId: leadId,
        }, lead.company);

        if (newOpp) {
            updateLead({ ...lead, status: LeadStatus.CALIFICADO });
        }

        return newOpp;
    }, [addOpportunity, updateLead, mainLeads]);

    const navLinkClasses = "flex items-center space-x-3 px-3 py-2.5 rounded-lg transition-colors";
    const activeClassName = `${navLinkClasses} bg-slate-700 text-white`;
    const inactiveClassName = `${navLinkClasses} text-slate-400 hover:bg-slate-700/50 hover:text-white`;

    const navItems = [
        { path: "/panel", icon: <ChartBarIcon className="h-5 w-5" />, label: "Panel" },
        { path: "/listado", icon: <TagIcon className="h-5 w-5" />, label: "Listado" },
        { path: "/opportunities", icon: <BriefcaseIcon className="h-5 w-5" />, label: "Oportunidades" },
        { path: "/clients", icon: <UserGroupIcon className="h-5 w-5" />, label: "Clientes" },
        { path: "/salespeople", icon: <UserIcon className="h-5 w-5" />, label: "Vendedores", adminOnly: true },
        { path: "/products", icon: <CubeIcon className="h-5 w-5" />, label: "Productos" },
        { path: "/agenda", icon: <CalendarIcon className="h-5 w-5" />, label: "Agenda" },
        { path: "/support", icon: <WrenchScrewdriverIcon className="h-5 w-5" />, label: "Soporte" },
        { path: "/management", icon: <CogIcon className="h-5 w-5" />, label: "Gestión", adminOnly: true },
    ].filter(item => currentUser?.role === 'admin' || !item.adminOnly);

    if (!currentUser) {
        return <Login onLogin={handleLogin} users={users} />;
    }

    if (requiresPasswordChange) {
        return <PasswordChange user={currentUser} onChangePassword={changeUserPassword} onLogout={() => handleLogout()} />;
    }

    return (
        <ReactRouterDOM.HashRouter>
            <div className="flex h-screen bg-slate-900 font-sans">
                {isMobileMenuOpen && <div className="fixed inset-0 bg-black/60 z-30 md:hidden" onClick={() => setIsMobileMenuOpen(false)} aria-hidden="true"></div>}

                <aside className={`w-64 bg-slate-800 text-white flex flex-col p-4 border-r border-slate-700/50 fixed inset-y-0 left-0 transform md:relative md:translate-x-0 transition-transform duration-300 ease-in-out z-40 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}`}>
                    <div className="flex items-center justify-between space-x-2 p-3 mb-6">
                         <div className="flex items-center space-x-2">
                            <svg className="h-8 w-8 text-cyan-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            <span className="text-xl font-bold">Black Medical</span>
                        </div>
                        <button className="md:hidden p-2" onClick={() => setIsMobileMenuOpen(false)} aria-label="Close menu"><XIcon className="h-6 w-6"/></button>
                    </div>
                    <nav className="flex-1 flex flex-col space-y-2 overflow-y-auto">
                        {navItems.map(item => (
                            <ReactRouterDOM.NavLink key={item.path} to={item.path} onClick={() => setIsMobileMenuOpen(false)} className={({ isActive }) => isActive ? activeClassName : inactiveClassName}>
                                {item.icon}<span>{item.label}</span>
                            </ReactRouterDOM.NavLink>
                        ))}
                    </nav>
                     <div className="mt-auto pt-4 border-t border-slate-700/50 space-y-2">
                        {currentUser.role === 'salesperson' && (
                            <>
                                <button onClick={handleExportWorkdayData} className={`${inactiveClassName} w-full !text-cyan-400 hover:!text-cyan-300`}>
                                    <DownloadIcon className="h-5 w-5" /><span>Exportar Jornada</span>
                                </button>
                                <button onClick={() => salespersonImportRef.current?.click()} className={`${inactiveClassName} w-full !text-green-400 hover:!text-green-300`}>
                                    <UploadIcon className="h-5 w-5" /><span>Importar Datos Admin</span>
                                </button>
                                <input
                                    type="file"
                                    ref={salespersonImportRef}
                                    onChange={handleImportSalespersonData}
                                    className="hidden"
                                    accept="application/json,.json"
                                />
                            </>
                        )}
                        <button onClick={() => setIsPasswordChangeModalOpen(true)} className={`${inactiveClassName} w-full`}>
                            <KeyIcon className="h-5 w-5" /><span>Cambiar Contraseña</span>
                        </button>
                        <button onClick={() => handleLogout()} className={`${inactiveClassName} w-full`}>
                            <LogoutIcon className="h-5 w-5" /><span>Cerrar Sesión</span>
                        </button>
                    </div>
                </aside>
                <div className="flex-1 flex flex-col overflow-hidden">
                    <header className="bg-slate-800/80 backdrop-blur-sm border-b border-slate-700/50 p-2 sm:p-3 flex items-center justify-between flex-shrink-0">
                        <button onClick={() => setIsMobileMenuOpen(true)} className="p-2 md:hidden" aria-label="Open menu">
                            <MenuIcon className="h-6 w-6 text-white"/>
                        </button>

                        <div className="hidden md:flex items-center space-x-2 ml-2">
                            <span className="text-slate-400">Bienvenido,</span>
                            <span className="text-white font-semibold">{currentUser.name}</span>
                        </div>

                        <div className="flex items-center space-x-2 md:hidden">
                            {/* This space is intentionally left for mobile layout balance, could add a logo here if needed */}
                        </div>

                    </header>
                    <main className="flex-1 overflow-y-auto">
                        <ReactRouterDOM.Routes>
                            <ReactRouterDOM.Route path="/" element={<ReactRouterDOM.Navigate to="/panel" />} />
                            <ReactRouterDOM.Route path="/panel" element={<Panel clientsCount={data.clients.length} leadsCount={data.leads.length} salespeopleCount={data.salespeople.length} productsCount={data.products.length} leads={data.leads} salespeople={data.salespeople} interactions={data.interactions} opportunities={data.opportunities} />}/>
                            <ReactRouterDOM.Route path="/clients" element={<Clients clients={data.clients} updateClient={updateClient} deleteClient={deleteClient} opportunities={data.opportunities} salespeople={data.salespeople} />} />
                            <ReactRouterDOM.Route path="/listado" element={<Listado user={currentUser} leads={data.leads} salespeople={data.salespeople} interactions={data.interactions} products={data.products} opportunities={data.opportunities} addLead={addLead} updateLead={updateLead} deleteLead={deleteLead} addInteraction={addInteraction} updateInteraction={updateInteraction} deleteInteraction={deleteInteraction} convertLeadToOpportunity={convertLeadToOpportunity} />} />
                            <ReactRouterDOM.Route path="/opportunities" element={<Opportunities user={currentUser} opportunities={data.opportunities} clients={data.clients} products={data.products} salespeople={data.salespeople} addOpportunity={addOpportunity} updateOpportunity={updateOpportunity} deleteOpportunity={deleteOpportunity} interactions={data.interactions} addInteraction={addInteraction} updateInteraction={updateInteraction} deleteInteraction={deleteInteraction} leads={data.leads} />} />
                            <ReactRouterDOM.Route path="/salespeople" element={<Salespeople salespeople={data.salespeople} leads={data.leads} tasks={data.tasks} addSalesperson={addSalesperson} updateSalesperson={updateSalesperson} deleteSalesperson={deleteSalesperson} />} />
                            <ReactRouterDOM.Route path="/products" element={<Products products={data.products} addProduct={addProduct} updateProduct={updateProduct} deleteProduct={deleteProduct} />} />
                            <ReactRouterDOM.Route path="/agenda" element={<Agenda user={currentUser} tasks={data.tasks} clients={data.clients} leads={data.leads} opportunities={data.opportunities} salespeople={data.salespeople} addTask={addTask} updateTask={updateTask} deleteTask={deleteTask} />} />
                            <ReactRouterDOM.Route path="/support" element={<Support tickets={data.supportTickets} clients={data.clients} addTicket={addTicket} updateTicket={updateTicket} deleteTicket={deleteTicket} />} />
                            <ReactRouterDOM.Route 
                                path="/management" 
                                element={
                                    <Management 
                                        onImport={handleMergeSalespersonData} 
                                        onFullRestore={handleFullBackupRestore} 
                                        onFullBackup={handleFullBackup}
                                        onResetData={handleResetData}
                                        onExportSalespersonBackup={handleExportSalespersonBackup}
                                        salespeople={data.salespeople}
                                    />} 
                                />
                        </ReactRouterDOM.Routes>
                    </main>
                </div>
            </div>
             <button
                onClick={() => setIsGlobalSearchOpen(true)}
                className="fixed bottom-4 right-4 sm:bottom-6 sm:right-6 bg-cyan-500 hover:bg-cyan-600 text-white w-14 h-14 sm:w-16 sm:h-16 rounded-full shadow-lg flex items-center justify-center transform transition-transform hover:scale-110 z-50"
                aria-label="Abrir Búsqueda Global"
            >
                <SearchIcon className="h-7 w-7 sm:h-8 sm:h-8" />
            </button>
            <GlobalSearch
                isOpen={isGlobalSearchOpen}
                onClose={() => setIsGlobalSearchOpen(false)}
                clients={mainClients}
                leads={mainLeads}
                opportunities={mainOpportunities}
                tasks={mainTasks}
            />
            {isPasswordChangeModalOpen && currentUser && (
                <UserPasswordChangeModal
                    isOpen={isPasswordChangeModalOpen}
                    onClose={() => setIsPasswordChangeModalOpen(false)}
                    user={currentUser}
                    onChangePassword={handleSelfPasswordChange}
                />
            )}
        </ReactRouterDOM.HashRouter>
    );
}

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import type { Opportunity, Client, Product, Salesperson, OpportunityProduct, User, Interaction, Lead } from '../types';
import { OpportunityStage, InteractionType } from '../types';
import PencilIcon from './icons/PencilIcon';
import TrashIcon from './icons/TrashIcon';
import ConfirmationModal from './ConfirmationModal';
import ChatBubbleLeftRightIcon from './icons/ChatBubbleLeftRightIcon';

interface OpportunitiesProps {
    user: User;
    opportunities: Opportunity[];
    clients: Client[];
    leads: Lead[];
    products: Product[];
    salespeople: Salesperson[];
    interactions: Interaction[];
    addOpportunity: (opportunity: Omit<Opportunity, 'id' | 'clientName'>, explicitClientName?: string) => Opportunity | null;
    updateOpportunity: (opportunity: Opportunity) => void;
    deleteOpportunity: (opportunityId: string) => void;
    addInteraction: (interaction: Omit<Interaction, 'id' | 'date'>) => void;
    updateInteraction: (interaction: Interaction) => void;
    deleteInteraction: (interactionId: string) => void;
}

const stageColors: Record<OpportunityStage, string> = {
    [OpportunityStage.PROSPECCION]: 'border-blue-500/50 bg-blue-500/10 text-blue-400',
    [OpportunityStage.PROPUESTA]: 'border-purple-500/50 bg-purple-500/10 text-purple-400',
    [OpportunityStage.NEGOCIACION]: 'border-yellow-500/50 bg-yellow-500/10 text-yellow-400',
    [OpportunityStage.GANADA]: 'border-green-500/50 bg-green-500/10 text-green-400',
    [OpportunityStage.PERDIDA]: 'border-red-500/50 bg-red-500/10 text-red-400',
};

const Opportunities: React.FC<OpportunitiesProps> = ({ user, opportunities, clients, leads, products, salespeople, interactions, addOpportunity, updateOpportunity, deleteOpportunity, addInteraction, updateInteraction, deleteInteraction }) => {
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingOpp, setEditingOpp] = useState<Opportunity | null>(null);

    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [oppToDeleteId, setOppToDeleteId] = useState<string | null>(null);

    const [isInteractionModalOpen, setIsInteractionModalOpen] = useState(false);
    const [selectedOpp, setSelectedOpp] = useState<Opportunity | null>(null);
    const initialInteractionState = { type: InteractionType.LLAMADA, notes: '', salespersonId: '' };
    const [newInteraction, setNewInteraction] = useState<{type: InteractionType, notes: string, salespersonId: string}>(initialInteractionState);
    const [editingInteraction, setEditingInteraction] = useState<Interaction | null>(null);
    const [interactionToDelete, setInteractionToDelete] = useState<Interaction | null>(null);
    const [isInteractionConfirmModalOpen, setIsInteractionConfirmModalOpen] = useState(false);

    const initialFormState = { clientId: '', salespersonId: user.role === 'salesperson' ? user.id : '', stage: OpportunityStage.PROSPECCION, closeDate: '', value: 0 };
    const [oppFormData, setOppFormData] = useState(initialFormState);
    const [oppProducts, setOppProducts] = useState<OpportunityProduct[]>([]);
    const [sortBy, setSortBy] = useState<'alpha' | 'recent'>('alpha');

    const location = useLocation();
    const navigate = useNavigate();

    const sortedOpportunities = useMemo(() => {
        const list = [...opportunities];
        if (sortBy === 'alpha') {
            return list.sort((a, b) => a.clientName.localeCompare(b.clientName));
        } else {
            return list.sort((a, b) => {
                const dateA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
                const dateB = b.createdAt ? new Date(b.createdAt).getTime() : 0;
                return dateB - dateA;
            });
        }
    }, [opportunities, sortBy]);

    useEffect(() => {
        if (location.hash) {
            const id = location.hash.substring(1);
            const element = document.getElementById(id);
            if (element) {
                element.scrollIntoView({ behavior: 'smooth', block: 'center' });
                element.classList.add('highlight-row');
                setTimeout(() => {
                    element.classList.remove('highlight-row');
                    navigate(location.pathname, { replace: true });
                }, 2500);
            }
        }
    }, [location.hash, navigate, opportunities]);

    useEffect(() => {
        if (isModalOpen) {
            if (editingOpp) {
                setOppFormData({
                    clientId: editingOpp.clientId || '',
                    salespersonId: editingOpp.salespersonId,
                    stage: editingOpp.stage,
                    closeDate: editingOpp.closeDate,
                    value: editingOpp.value,
                });
                setOppProducts(editingOpp.products);
            } else {
                setOppFormData(initialFormState);
                setOppProducts([]);
            }
        }
    }, [isModalOpen, editingOpp]);

    const handleOpenModal = (opp: Opportunity | null) => {
        setEditingOpp(opp);
        setIsModalOpen(true);
    };

    const handleCloseModal = () => {
        setIsModalOpen(false);
        setEditingOpp(null);
    };

    const handleOpenInteractionModal = (opp: Opportunity) => {
        setSelectedOpp(opp);
        setNewInteraction({ ...initialInteractionState, salespersonId: opp.salespersonId });
        setIsInteractionModalOpen(true);
    };

    const handleCloseInteractionModal = () => {
        setSelectedOpp(null);
        setIsInteractionModalOpen(false);
        setNewInteraction(initialInteractionState);
        setEditingInteraction(null);
    };

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setOppFormData(prev => ({ ...prev, [name]: name === 'value' ? parseFloat(value) || 0 : value }));
    };

    const handleAddProduct = () => {
        const select = document.getElementById('product-select-modal') as HTMLSelectElement;
        const quantityInput = document.getElementById('product-quantity-modal') as HTMLInputElement;
        const product = products.find(p => p.id === select.value);
        if (product && !oppProducts.find(p => p.productId === product.id)) {
            const quantity = parseInt(quantityInput.value) || 1;
            setOppProducts(current => [...current, { productId: product.id, productName: product.name, quantity, price: product.price }]);
        }
    };

    const handleRemoveProduct = (productId: string) => {
        setOppProducts(current => current.filter(p => p.productId !== productId));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();

        const submissionData = {
            ...oppFormData,
            products: oppProducts,
        };

        if (editingOpp) {
            updateOpportunity({ ...editingOpp, ...submissionData });
        } else {
             if (!oppFormData.clientId || !oppFormData.salespersonId || oppProducts.length === 0) {
                alert("Por favor, complete todos los campos y añada al menos un producto.");
                return;
            }
            addOpportunity(submissionData);
        }
        handleCloseModal();
    };

    const handleDeleteClick = (oppId: string) => {
        setOppToDeleteId(oppId);
        setIsConfirmModalOpen(true);
    };

    const handleConfirmDelete = () => {
        if (oppToDeleteId) {
            deleteOpportunity(oppToDeleteId);
        }
        setIsConfirmModalOpen(false);
        setOppToDeleteId(null);
    };

    const handleInteractionSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedOpp || !newInteraction.salespersonId) return;

        if (editingInteraction) {
            updateInteraction({ ...editingInteraction, ...newInteraction });
        } else {
            addInteraction({ ...newInteraction, opportunityId: selectedOpp.id });
        }

        setNewInteraction(initialInteractionState);
        setEditingInteraction(null);
    };

    const handleEditInteraction = (interaction: Interaction) => {
        setEditingInteraction(interaction);
        setNewInteraction({
            type: interaction.type,
            notes: interaction.notes,
            salespersonId: interaction.salespersonId,
        });
    };

    const handleDeleteInteractionClick = (interaction: Interaction) => {
        setInteractionToDelete(interaction);
        setIsInteractionConfirmModalOpen(true);
    };

    const handleConfirmInteractionDelete = () => {
        if (interactionToDelete) {
            deleteInteraction(interactionToDelete.id);
        }
        setIsInteractionConfirmModalOpen(false);
        setInteractionToDelete(null);
    };

    const handleCancelEdit = () => {
        setEditingInteraction(null);
        setNewInteraction(initialInteractionState);
    };

    const getSalespersonName = (salespersonId: string) => salespeople.find(sp => sp.id === salespersonId)?.name || 'No asignado';

    const getOppInteractions = (opp: Opportunity) => {
        return interactions
            .filter(i => i.opportunityId === opp.id || (opp.originalLeadId && i.leadId === opp.originalLeadId))
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    };

    return (
        <>
            <div className="p-4 sm:p-6 md:p-8 text-white">
                <div className="flex flex-col gap-4 sm:flex-row sm:justify-between sm:items-center mb-6">
                    <h1 className="text-2xl sm:text-3xl font-bold text-slate-100">Oportunidades</h1>

                    <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                        <div className="flex items-center gap-3 bg-slate-800 p-1.5 rounded-lg border border-slate-700 self-start sm:self-center">
                            <span className="text-sm text-slate-400 ml-2 hidden sm:inline">Ordenar por:</span>
                            <button 
                                onClick={() => setSortBy('alpha')}
                                className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all ${sortBy === 'alpha' ? 'bg-cyan-500 text-white' : 'text-slate-400 hover:text-white'}`}
                            >
                                A-Z
                            </button>
                            <button 
                                onClick={() => setSortBy('recent')}
                                className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all ${sortBy === 'recent' ? 'bg-cyan-500 text-white' : 'text-slate-400 hover:text-white'}`}
                            >
                                Recientes
                            </button>
                        </div>
                        <button onClick={() => handleOpenModal(null)} className="bg-cyan-500 hover:bg-cyan-600 text-white font-bold py-2 px-4 rounded-lg transition-colors flex items-center justify-center space-x-2 w-full sm:w-auto">
                            <span>+ Nueva Oportunidad</span>
                        </button>
                    </div>
                </div>

                <div className="bg-slate-800 rounded-lg shadow-lg overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="min-w-full text-left text-sm">
                            <thead className="bg-slate-700/50 text-slate-300 uppercase tracking-wider hidden md:table-header-group">
                                <tr>
                                    <th className="p-4">Cliente / Prospecto</th>
                                    <th className="p-4">Teléfono</th>
                                    <th className="p-4">Productos</th>
                                    <th className="p-4">Valor</th>
                                    <th className="p-4">Etapa</th>
                                    <th className="p-4">Acciones</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-700">
                                {sortedOpportunities.map(opp => {
                                    const client = opp.clientId ? clients.find(c => c.id === opp.clientId) : null;
                                    const originalLead = opp.originalLeadId ? leads.find(l => l.id === opp.originalLeadId) : null;

                                    const clientPhone = client?.phone || originalLead?.phone || 'N/A';
                                    const contactPerson = client?.contactPerson || originalLead?.name || 'N/A';

                                    const originalValue = opp.products.reduce((sum, p) => sum + p.price * p.quantity, 0);
                                    const hasDiscountOrIncrease = originalValue.toFixed(2) !== opp.value.toFixed(2);

                                    return (
                                    <tr key={opp.id} id={opp.id} className="hover:bg-slate-700/50 transition-colors block md:table-row mb-2 md:mb-0 bg-slate-800 md:bg-transparent rounded-lg md:rounded-none">
                                        <td className="p-4 font-medium text-slate-100 block md:table-cell" data-label="Cliente:">
                                            <div>
                                                {opp.clientName}
                                                {contactPerson !== 'N/A' && <p className="text-sm text-slate-400 font-normal">{contactPerson}</p>}
                                            </div>
                                        </td>
                                        <td className="p-4 text-slate-300 block md:table-cell" data-label="Teléfono:">
                                            {clientPhone !== 'N/A' ? (
                                                <a href={`tel:${clientPhone}`} className="text-cyan-400 hover:text-cyan-300">{clientPhone}</a>
                                            ) : (
                                                <span className="text-slate-500">N/A</span>
                                            )}
                                        </td>
                                        <td className="p-4 text-slate-300 block md:table-cell" data-label="Productos:">
                                            <ul className="list-disc list-inside">
                                               {opp.products.map(p => <li key={p.productId}>{p.productName} (x{p.quantity})</li>)}
                                            </ul>
                                        </td>
                                        <td className="p-4 font-medium block md:table-cell" data-label="Valor:">
                                            {hasDiscountOrIncrease ? (
                                                <div>
                                                    <span className="line-through text-slate-500 text-xs">
                                                        €{originalValue.toLocaleString('es-ES', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                                    </span>
                                                    <p className={`font-bold ${opp.value < originalValue ? 'text-orange-400' : 'text-yellow-400'}`}>
                                                        €{opp.value.toLocaleString('es-ES', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                                    </p>
                                                </div>
                                            ) : (
                                                <span className="text-green-400">
                                                    €{opp.value.toLocaleString('es-ES', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                                                </span>
                                            )}
                                        </td>
                                        <td className="p-4 block md:table-cell" data-label="Etapa:">
                                            <span className={`px-2 py-1 text-xs font-semibold border rounded-full ${stageColors[opp.stage]}`}>
                                                {opp.stage}
                                            </span>
                                        </td>
                                        <td className="p-4 block md:table-cell">
                                            <div className="flex items-center space-x-2">
                                                 <button onClick={() => handleOpenInteractionModal(opp)} className="p-2 text-cyan-400 hover:text-cyan-300 rounded-md hover:bg-slate-700" title="Ver/Añadir Interacciones"><ChatBubbleLeftRightIcon className="h-4 w-4" /></button>
                                                 <button onClick={() => handleOpenModal(opp)} className="p-2 text-yellow-400 hover:text-yellow-300 rounded-md hover:bg-slate-700" title="Editar"><PencilIcon className="h-4 w-4" /></button>
                                                 <button onClick={() => handleDeleteClick(opp.id)} className="p-2 text-red-400 hover:text-red-300 rounded-md hover:bg-slate-700" title="Eliminar"><TrashIcon className="h-4 w-4" /></button>
                                            </div>
                                        </td>
                                    </tr>
                                )})}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
            {isModalOpen && (
                 <div className="fixed inset-0 bg-black/60 z-50 flex justify-center items-center p-4">
                    <div className="bg-slate-800 rounded-lg shadow-xl p-6 w-full max-w-2xl border border-slate-700">
                        <h2 className="text-2xl font-bold text-white mb-6">{editingOpp ? 'Editar' : 'Nueva'} Oportunidad</h2>
                        <form onSubmit={handleSubmit} className="space-y-4">
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {editingOpp ? (
                                    <div>
                                        <label htmlFor="clientName-display" className="text-sm font-medium text-slate-300 mb-1 block">Cliente / Prospecto</label>
                                        <input
                                            id="clientName-display"
                                            type="text"
                                            value={editingOpp.clientName}
                                            className="w-full bg-slate-900/50 text-slate-300 p-3 rounded-md cursor-not-allowed border border-slate-700"
                                            disabled
                                        />
                                    </div>
                                ) : (
                                    <select name="clientId" value={oppFormData.clientId} onChange={handleInputChange} className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500" required>
                                        <option value="" disabled>Seleccione un Cliente</option>
                                        {clients.map(client => <option key={client.id} value={client.id}>{client.name}</option>)}
                                    </select>
                                )}
                                <select 
                                    name="salespersonId" 
                                    value={oppFormData.salespersonId} 
                                    onChange={handleInputChange} 
                                    className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500" 
                                    required
                                    disabled={user.role === 'salesperson'}
                                >
                                    <option value="" disabled>Seleccione un Vendedor</option>
                                    {salespeople.map(sp => <option key={sp.id} value={sp.id}>{sp.name}</option>)}
                                </select>
                            </div>
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <input type="date" name="closeDate" value={oppFormData.closeDate} onChange={handleInputChange} className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500" required />
                                <select name="stage" value={oppFormData.stage} onChange={handleInputChange} className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500">
                                    {Object.values(OpportunityStage).map(stage => <option key={stage} value={stage}>{stage}</option>)}
                                </select>
                            </div>

                             <div>
                                <label htmlFor="opp-value" className="text-sm font-medium text-slate-300 mb-1 block">Valor Total Manual (€)</label>
                                <input 
                                    id="opp-value"
                                    type="number"
                                    step="0.01"
                                    name="value"
                                    value={oppFormData.value || ''}
                                    onChange={handleInputChange}
                                    placeholder="Valor Total (€)" 
                                    className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500"
                                    required 
                                />
                                <p className="text-xs text-slate-400 mt-1">Este valor anula el cálculo automático de los productos. Ajústelo para reflejar descuentos o costes adicionales.</p>
                            </div>

                             <div className="bg-slate-700/50 p-4 rounded-lg">
                                <h3 className="text-lg font-semibold text-white mb-3">Productos</h3>
                                <div className="space-y-2 mb-4 max-h-32 overflow-y-auto">
                                    {oppProducts.map(p => (
                                        <div key={p.productId} className="flex items-center justify-between bg-slate-800 p-2 rounded">
                                            <span className="text-sm text-slate-200">{p.productName} (x{p.quantity})</span>
                                            <button type="button" onClick={() => handleRemoveProduct(p.productId)} className="text-red-400 hover:text-red-300 font-bold">&times;</button>
                                        </div>
                                    ))}
                                    {oppProducts.length === 0 && <p className="text-slate-400 text-sm text-center">Añada productos a la oportunidad.</p>}
                                </div>
                                <div className="flex items-end gap-2">
                                    <div className="flex-grow">
                                        <label htmlFor="product-select-modal" className="text-xs text-slate-400">Producto</label>
                                        <select id="product-select-modal" className="w-full bg-slate-700 text-white p-2 rounded-md focus:outline-none focus:ring-1 focus:ring-cyan-500">
                                            {products.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                                        </select>
                                    </div>
                                    <div>
                                        <label htmlFor="product-quantity-modal" className="text-xs text-slate-400">Cant.</label>
                                        <input id="product-quantity-modal" type="number" defaultValue="1" min="1" className="w-20 bg-slate-700 text-white p-2 rounded-md focus:outline-none focus:ring-1 focus:ring-cyan-500" />
                                    </div>
                                    <button type="button" onClick={handleAddProduct} className="px-3 py-2 bg-blue-600 hover:bg-blue-700 rounded-md text-sm whitespace-nowrap">Añadir</button>
                                </div>
                            </div>

                            <div className="flex justify-end space-x-4 pt-4">
                                <button type="button" onClick={handleCloseModal} className="py-2 px-4 bg-slate-600 hover:bg-slate-500 rounded-md text-white font-semibold transition-colors">Cancelar</button>
                                <button type="submit" className="py-2 px-4 bg-cyan-500 hover:bg-cyan-600 rounded-md text-white font-semibold transition-colors">{editingOpp ? 'Actualizar' : 'Guardar'}</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
            {isInteractionModalOpen && selectedOpp && (
                 <div className="fixed inset-0 bg-black/60 z-50 flex justify-center items-start p-4 pt-10 sm:pt-16">
                    <div className="bg-slate-800 rounded-lg shadow-xl p-6 w-full max-w-2xl border border-slate-700">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl sm:text-2xl font-bold text-white">Interacciones: {selectedOpp.clientName}</h2>
                            <button onClick={handleCloseInteractionModal} className="text-slate-400 hover:text-white text-3xl leading-none">&times;</button>
                        </div>

                        <form onSubmit={handleInteractionSubmit} className="space-y-4 bg-slate-700/50 p-4 rounded-lg mb-6">
                             <h3 className="text-lg font-semibold text-white">{editingInteraction ? 'Editar Interacción' : 'Añadir Nueva Interacción'}</h3>
                             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <select name="type" value={newInteraction.type} onChange={e => setNewInteraction(p => ({...p, type: e.target.value as InteractionType}))} className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500">
                                    {Object.values(InteractionType).map(type => <option key={type} value={type}>{type}</option>)}
                                </select>
                                <select 
                                    name="salespersonId" 
                                    value={newInteraction.salespersonId} 
                                    onChange={e => setNewInteraction(p => ({...p, salespersonId: e.target.value}))} 
                                    className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500" 
                                    required
                                    disabled={user.role === 'salesperson'}
                                >
                                    <option value="" disabled>Realizada por...</option>
                                    {salespeople.map(sp => <option key={sp.id} value={sp.id}>{sp.name}</option>)}
                                </select>
                            </div>
                            <textarea name="notes" value={newInteraction.notes} onChange={e => setNewInteraction(p => ({...p, notes: e.target.value}))} placeholder="Notas de la interacción..." className="w-full bg-slate-700 text-white p-3 rounded-md focus:outline-none focus:ring-2 focus:ring-cyan-500 h-20" required />
                            <div className="flex justify-end items-center gap-4">
                                {editingInteraction && (
                                    <button type="button" onClick={handleCancelEdit} className="py-2 px-4 bg-slate-600 hover:bg-slate-500 rounded-md text-white font-semibold transition-colors">Cancelar Edición</button>
                                )}
                                <button type="submit" className="py-2 px-4 bg-cyan-500 hover:bg-cyan-600 rounded-md text-white font-semibold transition-colors">
                                    {editingInteraction ? 'Actualizar' : 'Guardar'} Interacción
                                </button>
                            </div>
                        </form>

                        <div className="space-y-4 max-h-64 overflow-y-auto pr-2">
                           {getOppInteractions(selectedOpp).map(interaction => (
                               <div key={interaction.id} className="bg-slate-900/50 p-4 rounded-lg group">
                                   <div className="flex justify-between items-start text-sm mb-2">
                                       <div>
                                            <span className="font-bold text-cyan-400">{interaction.type}</span>
                                            <span className="text-slate-400 ml-4">{new Date(interaction.date).toLocaleString()}</span>
                                        </div>
                                        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                           <button onClick={() => handleEditInteraction(interaction)} className="p-1 text-yellow-400 hover:text-yellow-300 rounded-md hover:bg-slate-700" title="Editar Interacción"><PencilIcon className="h-4 w-4" /></button>
                                           <button onClick={() => handleDeleteInteractionClick(interaction)} className="p-1 text-red-400 hover:text-red-300 rounded-md hover:bg-slate-700" title="Eliminar Interacción"><TrashIcon className="h-4 w-4" /></button>
                                       </div>
                                   </div>
                                   <p className="text-slate-200 whitespace-pre-wrap">{interaction.notes}</p>
                                   <p className="text-right text-xs text-slate-500 mt-2">por {getSalespersonName(interaction.salespersonId)}</p>
                               </div>
                           ))}
                           {getOppInteractions(selectedOpp).length === 0 && <p className="text-slate-400 text-center py-4">No hay interacciones registradas.</p>}
                        </div>
                    </div>
                </div>
            )}
             <ConfirmationModal
                isOpen={isConfirmModalOpen}
                onClose={() => setIsConfirmModalOpen(false)}
                onConfirm={handleConfirmDelete}
                title="Confirmar Eliminación de Oportunidad"
                message={
                    oppToDeleteId ? (
                        <>
                            ¿Está seguro de que desea eliminar la oportunidad para "<strong>{opportunities.find(o => o.id === oppToDeleteId)?.clientName}</strong>"?
                            <br/><br/>
                            <span className="font-bold">La tarea asociada en el calendario y las interacciones de esta oportunidad también se eliminarán.</span>
                        </>
                    ) : ''
                }
            />
            <ConfirmationModal
                isOpen={isInteractionConfirmModalOpen}
                onClose={() => setIsInteractionConfirmModalOpen(false)}
                onConfirm={handleConfirmInteractionDelete}
                title="Confirmar Eliminación de Interacción"
                message="¿Está seguro de que desea eliminar esta interacción? Esta acción no se puede deshacer."
            />
        </>
    );
};

export default Opportunities;

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import type { Lead, Salesperson, Interaction, Product, OpportunityProduct, User, Opportunity } from '../types';
import { LeadStatus, InteractionType, OpportunityStage } from '../types';
import ChatBubbleLeftRightIcon from './icons/ChatBubbleLeftRightIcon';
import PencilIcon from './icons/PencilIcon';
import TrashIcon from './icons/TrashIcon';
import CurrencyDollarIcon from './icons/CurrencyDollarIcon';
import ConfirmationModal from './ConfirmationModal';

interface ListadoProps {
    user: User;
    leads: Lead[];
    salespeople: Salesperson[];
    interactions: Interaction[];
    products: Product[];
    opportunities: Opportunity[];
    addLead: (lead: Omit<Lead, 'id'>) => void;
    updateLead: (lead: Lead) => void;
    deleteLead: (leadId: string) => void;
    addInteraction: (interaction: Omit<Interaction, 'id' | 'date'>) => void;
    updateInteraction: (interaction: Interaction) => void;
    deleteInteraction: (interactionId: string) => void;
    convertLeadToOpportunity: (leadId: string, opportunityData: { products: OpportunityProduct[], closeDate: string, stage: OpportunityStage, salespersonId: string }) => Opportunity | null;
}

const statusColors: Record<LeadStatus, string> = {
    [LeadStatus.NUEVO]: 'bg-blue-500/20 text-blue-300',
    [LeadStatus.CONTACTADO]: 'bg-yellow-500/20 text-yellow-300',
    [LeadStatus.CALIFICADO]: 'bg-green-500/20 text-green-300',
    [LeadStatus.PERDIDO]: 'bg-red-500/20 text-red-300',
};

const Listado: React.FC<ListadoProps> = ({ user, leads, salespeople, interactions, products, opportunities, addLead, updateLead, deleteLead, addInteraction, updateInteraction, deleteInteraction, convertLeadToOpportunity }) => {
    const [isLeadModalOpen, setIsLeadModalOpen] = useState(false);
    const [isInteractionModalOpen, setIsInteractionModalOpen] = useState(false);
    const [isConvertModalOpen, setIsConvertModalOpen] = useState(false);
    const [isConfirmModalOpen, setIsConfirmModalOpen] = useState(false);
    const [leadToDeleteId, setLeadToDeleteId] = useState<string | null>(null);

    const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
    const [editingLead, setEditingLead] = useState<Lead | null>(null);

    const initialLeadState: Omit<Lead, 'id'> = { name: '', company: '', email: '', phone: '', source: '', status: LeadStatus.NUEVO, salespersonId: user.role === 'salesperson' ? user.id : '' };
    const [leadFormData, setLeadFormData] = useState<Omit<Lead, 'id'>>(initialLeadState);

    const initialInteractionState = { type: InteractionType.LLAMADA, notes: '', salespersonId: '' };
    const [newInteraction, setNewInteraction] = useState<{type: InteractionType, notes: string, salespersonId: string}>(initialInteractionState);
    const [editingInteraction, setEditingInteraction] = useState<Interaction | null>(null);
    const [interactionToDelete, setInteractionToDelete] = useState<Interaction | null>(null);
    const [isInteractionConfirmModalOpen, setIsInteractionConfirmModalOpen] = useState(false);


    const [opportunityProducts, setOpportunityProducts] = useState<OpportunityProduct[]>([]);
    const [oppDetails, setOppDetails] = useState({ closeDate: '', stage: OpportunityStage.PROSPECCION });

    const [newOppProduct, setNewOppProduct] = useState({ productId: '', quantity: 1 });

    const [sortBy, setSortBy] = useState<'alpha' | 'recent'>('alpha');

    const location = useLocation();
    const navigate = useNavigate();

    const formatWhatsAppLink = (phone: string) => {
        const cleanPhone = phone.replace(/\D/g, '');
        return `https://wa.me/${cleanPhone}`;
    };

    const sortedLeads = useMemo(() => {
        const list = [...leads];
        if (sortBy === 'alpha') {
            return list.sort((a, b) => a.name.localeCompare(b.name));
        } else {
            return list.sort((a, b) => {
                const dateA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
                const dateB = b.createdAt ? new Date(b.createdAt).getTime() : 0;
                return dateB - dateA;
            });
        }
    }, [leads, sortBy]);

    useEffect(() => {
        if (location.hash) {
            const id = location.hash.substring(1);
            const element = document.getElementById(id);
            if (element) {
                element.scrollIntoView({ behavior: 'smooth', block: 'center' });
                element.classList.add('highlight-row');
                setTimeout(() => {
                    element.classList.remove('highlight-row');
                    navigate(location.pathname, { replace: true });
                }, 2500);
            }
        }
    }, [location.hash, navigate, leads]);

    const handleProductInputChange = (field: 'productId' | 'quantity', value: string) => {
        if (field === 'quantity') {
            const numValue = parseInt(value, 10);
            setNewOppProduct(prev => ({ ...prev, [field]: numValue >= 1 ? numValue : 1 }));
        } else {
            setNewOppProduct(prev => ({ ...prev, [field]: value }));
        }
    };

    const handleAddProduct = () => {
        const product = products.find(p => p.id === newOppProduct.productId);
        if (product && newOppProduct.quantity > 0) {
            setOpportunityProducts(current => [...current, { 
                productId: product.id, 
                productName: product.name, 
                quantity: newOppProduct.quantity, 
                price: product.price 
            }]);
            setNewOppProduct({ productId: '', quantity: 1 }); // Reset for next entry
        }
    };

    const handleOpenLeadModal = (lead: Lead | null) => {
        setEditingLead(lead);
        setLeadFormData(lead ? { ...lead } : initialLeadState);
        setIsLeadModalOpen(true);
    };
    const handleCloseLeadModal = () => {
        setIsLeadModalOpen(false);
        setEditingLead(null);
    };

    const handleOpenInteractionModal = (lead: Lead) => {
        setSelectedLead(lead);
        setIsInteractionModalOpen(true);
        setNewInteraction({ ...initialInteractionState, salespersonId: lead.salespersonId });
    };
    const handleCloseInteractionModal = () => {
        setSelectedLead(null);
        setIsInteractionModalOpen(false);
        setNewInteraction(initialInteractionState);
        setEditingInteraction(null);
    };

    const handleOpenConvertModal = (lead: Lead) => {
        setSelectedLead(lead);
        setIsConvertModalOpen(true);
        setOpportunityProducts([]);
        setOppDetails({ closeDate: '', stage: OpportunityStage.PROSPECCION });
        setNewOppProduct({ productId: '', quantity: 1 });
    };

    const handleCloseConvertModal = () => {
        setSelectedLead(null);
        setIsConvertModalOpen(false);
        setOpportunityProducts([]);
        setOppDetails({ closeDate: '', stage: OpportunityStage.PROSPECCION });
    };

    const handleLeadSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!leadFormData.salespersonId) return alert("Por favor, asigne el prospecto a un vendedor.");
        if (editingLead) {
            updateLead({ ...editingLead, ...leadFormData });
        } else {
            addLead(leadFormData);
        }
        handleCloseLeadModal();
    };

    const handleInteractionSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedLead || !newInteraction.salespersonId) return;

        if(editingInteraction) {
            updateInteraction({ ...editingInteraction, ...newInteraction });
        } else {
            addInteraction({ ...newInteraction, leadId: selectedLead.id });
        }

        setNewInteraction(initialInteractionState); 
        setEditingInteraction(null);
    };

    const handleConvertSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedLead || opportunityProducts.length === 0 || !oppDetails.closeDate) {
            return alert("Por favor, complete todos los campos de la oportunidad.");
        }
        const newOpportunity = convertLeadToOpportunity(selectedLead.id, {
            ...oppDetails,
            products: [...opportunityProducts],
            salespersonId: selectedLead.salespersonId
        });
        handleCloseConvertModal();
        if (newOpportunity) {
            navigate(`/opportunities#${newOpportunity.id}`);
        } else {
            alert("Error al convertir el prospecto. Por favor, inténtelo de nuevo.");
        }
    };

    const handleDeleteClick = (leadId: string) => {
        setLeadToDeleteId(leadId);
        setIsConfirmModalOpen(true);
    };

    const handleConfirmDelete = () => {
        if (leadToDeleteId) {
            deleteLead(leadToDeleteId);
        }
        setIsConfirmModalOpen(false);
        setLeadToDeleteId(null);
    };

    const handleEditInteraction = (interaction: Interaction) => {
        setEditingInteraction(interaction);
        setNewInteraction({
            type: interaction.type,
            notes: interaction.notes,
            salespersonId: interaction.salespersonId,
        });
    };

    const handleDeleteInteractionClick = (interaction: Interaction) => {
        setInteractionToDelete(interaction);
        setIsInteractionConfirmModalOpen(true);
    };

    const handleConfirmInteractionDelete = () => {
        if (interactionToDelete) {
            deleteInteraction(interactionToDelete.id);
        }
        setIsInteractionConfirmModalOpen(false);
        setInteractionToDelete(null);
    };

    const handleCancelEdit = () => {
        setEditingInteraction(null);
        setNewInteraction(initialInteractionState);
    };

    const getSalespersonName = (salespersonId: string) => salespeople.find(sp => sp.id === salespersonId)?.name || 'No asignado';

    const getLeadInteractions = (leadId: string) => {
        const correspondingOpportunity = opportunities.find(o => o.originalLeadId === leadId);

        return interactions
            .filter(i =>
                i.leadId === leadId ||
                (correspondingOpportunity && i.opportunityId === correspondingOpportunity.id)
            )
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
    };

    return (
        <>
            <div className="p-4 sm:p-6 md:p-8 text-white">
                <div className="flex flex-col gap-4 sm:flex-row sm:justify-between sm:items-center mb-6">
                    <h1 className="text-2xl sm:text-3xl font-bold text-slate-100">Listado de Prospectos</h1>

                    <div className="flex flex-col sm:flex-row gap-4 w-full sm:w-auto">
                        <div className="flex items-center gap-3 bg-slate-800 p-1.5 rounded-lg border border-slate-700 self-start sm:self-center">
                            <span className="text-sm text-slate-400 ml-2 hidden sm:inline">Ordenar por:</span>
                            <button 
                                onClick={() => setSortBy('alpha')}
                                className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all ${sortBy === 'alpha' ? 'bg-cyan-500 text-white' : 'text-slate-400 hover:text-white'}`}
                            >
                                A-Z
                            </button>
                            <button 
                                onClick={() => setSortBy('recent')}
                                className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all ${sortBy === 'recent' ? 'bg-cyan-500 text-white' : 'text-slate-400 hover:text-white'}`}
                            >
                                Recientes
                            </button>
                        </div>
                        <button onClick={() => handleOpenLeadModal(null)} className="bg-cyan-500 hover:bg-cyan-600 text-white font-bold py-2 px-4 rounded-lg transition-colors flex items-center justify-center space-x-2 w-full sm:w-auto">
                            <span>+ Nuevo Prospecto</span>
                        </button>
                    </div>
                </div>

                 <div className="bg-slate-800 rounded-lg shadow-lg overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="min-w-full text-left text-sm">
                            <thead className="bg-slate-700/50 text-slate-300 uppercase tracking-wider hidden md:table-header-group">
                                <tr>
                                    <th className="p-4">Nombre</th>
                                    <th className="p-4">Empresa</th>
                                    <th className="p-4">Teléfono</th>
                                    <th className="p-4">Asignado a</th>
                                    <th className="p-4">Estado</th>
                                    <th className="p-4">Acciones</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-700">
                                {sortedLeads.map(lead => (
                                    <tr key={lead.id} id={lead.id} className="hover:bg-slate-700/50 transition-colors block md:table-row mb-2 md:mb-0 bg-slate-800 md:bg-transparent rounded-lg md:rounded-none">
                                        <td className="p-4 font-medium text-slate-100 block md:table-cell" data-label="Nombre: ">
                                            <p>{lead.name}</p>
                                            <a href={`mailto:${lead.email}`} className="text-cyan-400 hover:text-cyan-300 text-xs">{lead.email}</a>
                                        </td>
                                        <td className="p-4 text-slate-300 block md:table-cell" data-label="Empresa: ">{lead.company}</td>
                                        <td className="p-4 text-slate-300 block md:table-cell" data-label="Teléfono: ">
                                          {lead.phone ? (
                                             <a 
                                                href={formatWhatsAppLink(lead.phone)} 
                                                target="_blank" 
                                                rel="noopener noreferrer" 
                                                className="flex items-center gap-1.5 text-green-400 hover:text-green-300 group"
                                             >
                                                <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
                                                <span className="group-hover:underline">{lead.phone}</span>
                                             </a>
