import React, { useState, useEffect } from 'react';
import type { Product, Lead, WhatsAppTemplate } from '../types';
import UploadIcon from './icons/UploadIcon';

interface WhatsAppProductModalProps {
    isOpen: boolean;
    onClose: () => void;
    lead: Lead;
    products: Product[];
    templates: WhatsAppTemplate[];
    onSend: (productId: string, message: string) => void;
}

const WhatsAppProductModal: React.FC<WhatsAppProductModalProps> = ({ isOpen, onClose, lead, products, templates, onSend }) => {
    const [selectedProductId, setSelectedProductId] = useState<string>('');
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>('');
    const [message, setMessage] = useState<string>('');
    const [imageCopied, setImageCopied] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setSelectedProductId('');
            setSelectedTemplateId('');
            setMessage('');
            setImageCopied(false);
        }
    }, [isOpen]);

    // Function to generate message based on template and product
    const generateMessage = (prodId: string, tempId: string) => {
        const product = products.find(p => p.id === prodId);
        const template = templates.find(t => t.id === tempId);

        if (!product) {
            setMessage('');
            return;
        }

        let content = '';

        if (template) {
            content = template.content;
            // Replace variables
            content = content.replace(/{NOMBRE_CLIENTE}/g, lead.name || '');
            content = content.replace(/{EMPRESA_CLIENTE}/g, lead.company || '');
            content = content.replace(/{NOMBRE_PRODUCTO}/g, product.name || '');
            content = content.replace(/{PRECIO_PRODUCTO}/g, product.price.toLocaleString('es-ES'));
            content = content.replace(/{DESCRIPCION_PRODUCTO}/g, product.description || '');
        } else {
            // Default template if none selected
            content = `Hola ${lead.name}, gusto en saludarte.\n\nTe comparto la información del equipo médico que podría interesarte:\n\n*${product.name}*\n${product.description}\n\n*Precio:* €${product.price.toLocaleString('es-ES')}\n\nQuedo atento a tus dudas.`;
        }

        setMessage(content);
    };

    const handleProductChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const productId = e.target.value;
        setSelectedProductId(productId);
        generateMessage(productId, selectedTemplateId);
        setImageCopied(false);
    };

    const handleTemplateChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const templateId = e.target.value;
        setSelectedTemplateId(templateId);
        generateMessage(selectedProductId, templateId);
    };

    const copyImageToClipboard = async () => {
        const product = products.find(p => p.id === selectedProductId);
        if (product && product.image) {
            try {
                // Convert Base64 to Blob
                const res = await fetch(product.image);
                const blob = await res.blob();

                // Write to clipboard
                await navigator.clipboard.write([
                    new ClipboardItem({
                        [blob.type]: blob,
                    }),
                ]);
                setImageCopied(true);
            } catch (err) {
                console.error("Error al copiar imagen:", err);
                alert("No se pudo copiar la imagen automáticamente. Por favor, descárgala o adjúntala manualmente.");
            }
        }
    };

    const handleSend = () => {
        if (!lead.phone) return alert("Este prospecto no tiene número de teléfono.");

        const cleanPhone = lead.phone.replace(/\D/g, '');
        const encodedMessage = encodeURIComponent(message);
        const url = `https://wa.me/${cleanPhone}?text=${encodedMessage}`;

        // Open WhatsApp
        window.open(url, '_blank');

        // Log interaction in CRM
        onSend(selectedProductId, message);
        onClose();
    };

    const selectedProduct = products.find(p => p.id === selectedProductId);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex justify-center items-center p-4">
