                            <div className="flex-1 space-y-2">
                                <label className="block text-xs font-semibold text-slate-400 uppercase">Mensaje (Editable)</label>
                                <textarea 
                                    value={message}
                                    onChange={(e) => setMessage(e.target.value)}
                                    className="w-full h-32 bg-slate-800 text-slate-200 p-2 rounded-md text-sm focus:outline-none focus:ring-1 focus:ring-green-500 resize-none font-mono"
                                />
                            </div>
                        </div>
                    )}

                    <div className="bg-blue-500/10 border border-blue-500/30 p-3 rounded-md">
                        <p className="text-blue-200 text-xs flex items-start gap-2">
                            <span className="font-bold text-lg leading-none">ℹ️</span>
                            <span>
                                <strong>Nota:</strong> WhatsApp Web no permite adjuntar imágenes automáticamente desde un enlace. 
                                <br/>Use el botón <strong>"1. Copiar Foto"</strong> y luego pegue la imagen (Ctrl+V) en el chat de WhatsApp.
                            </span>
                        </p>
                    </div>

                    <div className="flex flex-col sm:flex-row gap-3 pt-2">
                        {selectedProduct?.image && (
                            <button 
                                onClick={copyImageToClipboard}
                                className={`flex-1 py-3 px-4 rounded-md font-semibold transition-all flex items-center justify-center gap-2 ${imageCopied ? 'bg-green-600 text-white' : 'bg-slate-600 hover:bg-slate-500 text-white'}`}
                            >
                                {imageCopied ? '¡Foto Copiada!' : (
                                    <>
                                        <span>1. Copiar Foto</span>
                                    </>
                                )}
                            </button>
                        )}

                        <button 
                            onClick={handleSend}
                            disabled={!selectedProductId}
                            className="flex-[2] py-3 px-4 bg-green-500 hover:bg-green-600 disabled:bg-slate-600 disabled:cursor-not-allowed text-white font-bold rounded-md transition-colors flex items-center justify-center gap-2 shadow-lg shadow-green-500/20"
                        >
                            <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
                            {selectedProduct?.image ? '2. Abrir WhatsApp y Pegar' : 'Enviar Mensaje WhatsApp'}
