    }, []); // Empty dependency array ensures this runs only once on mount.


    const setAuth = (user: User | null) => {
        if (user) {
            sessionStorage.setItem('currentUser', JSON.stringify(user));
        } else {
            sessionStorage.removeItem('currentUser');
        }
