    }, [currentUser, mainClients, mainLeads, mainProducts, mainOpportunities, mainTasks, mainSupportTickets, mainSalespeople, mainInteractions, mainWhatsAppTemplates]);


    const handleLogin = (userId: string, pass: string): boolean => {
