        return false;
    };

    const changeUserPassword = (userId: string, newPassword: string) => {
        let updatedUser: User | null = null;
        setUsers(prevUsers => prevUsers.map(u => {
            if (u.id === userId) {
                updatedUser = { ...u, password_DO_NOT_USE: newPassword, mustChangePassword: false };
                return updatedUser;
            }
            return u;
        }));

        if (updatedUser) {
            setAuth(updatedUser);
