    };

    const handleExportSalespersonBackup = (salespersonId: string) => {
        if (currentUser?.role !== 'admin' || !salespersonId) return;

        const salesperson = mainSalespeople.find(sp => sp.id === salespersonId);
        if (!salesperson) {
