import React, { useState, useEffect } from 'react';
import type { Product, Lead, WhatsAppTemplate } from '../types';
import UploadIcon from './icons/UploadIcon';

interface WhatsAppProductModalProps {
    isOpen: boolean;
    onClose: () => void;
    lead: Lead;
    products: Product[];
    templates: WhatsAppTemplate[];
    onSend: (productId: string, message: string) => void;
}

export const WhatsAppProductModal: React.FC<WhatsAppProductModalProps> = ({ isOpen, onClose, lead, products, templates, onSend }) => {
    const [selectedProductId, setSelectedProductId] = useState<string>('');
    const [selectedTemplateId, setSelectedTemplateId] = useState<string>('');
    const [message, setMessage] = useState<string>('');
    const [imageCopied, setImageCopied] = useState(false);
    const [isCopying, setIsCopying] = useState(false);

    useEffect(() => {
        if (isOpen) {
            setSelectedProductId('');
            setSelectedTemplateId('');
            setMessage('');
            setImageCopied(false);
            setIsCopying(false);
        }
    }, [isOpen]);

    // Function to generate message based on template and product
    const generateMessage = (prodId: string, tempId: string) => {
        const product = products.find(p => p.id === prodId);
        const template = templates.find(t => t.id === tempId);

        if (!product) {
            setMessage('');
            return;
        }

        let content = '';

        if (template) {
            content = template.content;
            // Replace variables
            content = content.replace(/{NOMBRE_CLIENTE}/g, lead.name || '');
            content = content.replace(/{EMPRESA_CLIENTE}/g, lead.company || '');
            content = content.replace(/{NOMBRE_PRODUCTO}/g, product.name || '');
            content = content.replace(/{PRECIO_PRODUCTO}/g, product.price.toLocaleString('es-ES'));
            content = content.replace(/{DESCRIPCION_PRODUCTO}/g, product.description || '');
        } else {
            // Default template if none selected
            content = `Hola ${lead.name}, gusto en saludarte.\n\nTe comparto la información del equipo médico que podría interesarte:\n\n*${product.name}*\n${product.description}\n\n*Precio:* €${product.price.toLocaleString('es-ES')}\n\nQuedo atento a tus dudas.`;
        }

        setMessage(content);
    };

    const handleProductChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const productId = e.target.value;
        setSelectedProductId(productId);
        generateMessage(productId, selectedTemplateId);
        setImageCopied(false);
    };

    const handleTemplateChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const templateId = e.target.value;
        setSelectedTemplateId(templateId);
        generateMessage(selectedProductId, templateId);
    };

    const copyImageToClipboard = async () => {
        const product = products.find(p => p.id === selectedProductId);
        if (product && product.image) {
            setIsCopying(true);
            try {
                // 1. Crear elemento de imagen para cargar la data
                const img = new Image();
                // Permitir CORS por si la imagen viene de una URL externa, aunque sea base64
                img.crossOrigin = "anonymous"; 
                img.src = product.image;

                // Esperar a que la imagen cargue completamente
                await new Promise((resolve, reject) => {
                    img.onload = resolve;
                    img.onerror = () => reject(new Error("No se pudo cargar la imagen fuente."));
                });

                // 2. Dibujar en Canvas para estandarizar
                const canvas = document.createElement('canvas');
                canvas.width = img.naturalWidth;
                canvas.height = img.naturalHeight;
                const ctx = canvas.getContext('2d');
                if (!ctx) throw new Error("Error de contexto Canvas");

                // IMPORTANTE: Rellenar fondo blanco.
                // WhatsApp a veces falla con imágenes transparentes (PNG) copiadas desde el portapapeles.
                ctx.fillStyle = '#FFFFFF';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                ctx.drawImage(img, 0, 0);

                // 3. Convertir explícitamente a PNG (Formato universal para portapapeles)
                const blob = await new Promise<Blob | null>(resolve => canvas.toBlob(resolve, 'image/png', 1.0));

                if (!blob) throw new Error("Error al generar el archivo de imagen");

                // 4. Escribir al portapapeles usando ClipboardItem
                const item = new ClipboardItem({ 'image/png': blob });
                await navigator.clipboard.write([item]);

                setImageCopied(true);

                // Resetear estado visual después de 3 seg
                setTimeout(() => {
                    setImageCopied(false);
                }, 3000);

            } catch (err) {
                console.error("Error al copiar imagen:", err);
                alert("Tu navegador no permitió copiar la imagen automáticamente. Intenta descargarla o usar otro navegador.");
            } finally {
                setIsCopying(false);
            }
        }
    };

    const handleSend = () => {
        if (!lead.phone) return alert("Este prospecto no tiene número de teléfono.");

        const cleanPhone = lead.phone.replace(/\D/g, '');
        const encodedMessage = encodeURIComponent(message);
        const url = `https://wa.me/${cleanPhone}?text=${encodedMessage}`;

        // Open WhatsApp
        window.open(url, '_blank');

        // Log interaction in CRM
        onSend(selectedProductId, message);
        onClose();
    };

    const selectedProduct = products.find(p => p.id === selectedProductId);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex justify-center items-center p-4">
            <div className="bg-slate-800 rounded-lg shadow-xl p-6 w-full max-w-lg border border-slate-700">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        <svg className="w-6 h-6 text-green-500" fill="currentColor" viewBox="0 0 24 24"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
                        {selectedProduct?.image ? '2. Abrir WhatsApp y Pegar' : 'Enviar Mensaje WhatsApp'}
